import { createAuthPlugin } from "@better-auth-ui/core"
import {
  organizationPlugin as coreOrganizationPlugin,
  type OrganizationLocalization,
  type OrganizationPluginOptions
} from "@better-auth-ui/core/plugins/organization"
import { BriefcaseBusiness } from "lucide-solid"
import type { Component } from "solid-js"
import { OrganizationsSettings } from "@/components/auth/organization/organizations-settings"

export type SolidSettingsTab = {
  view: string
  tabLabel: Component
  component: Component
}

export const organizationPlugin = createAuthPlugin(
  coreOrganizationPlugin.id,
  (options: OrganizationPluginOptions = {}) => {
    const core = coreOrganizationPlugin(options)

    return {
      ...core,
      localization: core.localization as OrganizationLocalization,
      settingsTabs: [
        {
          view: "organizations",
          tabLabel: () => (
            <span class="inline-flex items-center gap-1">
              <BriefcaseBusiness class="size-4 text-muted-foreground" />
              {core.localization.organizations}
            </span>
          ),
          component: OrganizationsSettings
        }
      ] satisfies SolidSettingsTab[]
    }
  }
)

import { cn } from "@/lib/utils"
import { Organizations } from "./organizations"
import { UserInvitations } from "./user-invitations"

export type OrganizationsSettingsProps = {
  class?: string
}

export function OrganizationsSettings(props: OrganizationsSettingsProps = {}) {
  return (
    <div class={cn("flex w-full flex-col gap-4 md:gap-6", props.class)}>
      <Organizations />
      <UserInvitations />
    </div>
  )
}

import type { OrganizationLocalization } from "@better-auth-ui/core/plugins/organization"
import { useAuth } from "@better-auth-ui/solid"
import type { OrganizationAuthClient } from "@better-auth-ui/solid/plugins/organization"
import {
  useAcceptInvitation,
  useRejectInvitation
} from "@better-auth-ui/solid/plugins/organization"
import { Check, Clock, X } from "lucide-solid"
import { Button } from "@/components/ui/button"
import { organizationPlugin } from "@/lib/auth/organization-plugin"

type RoleMap = Record<string, string>

type UserInvitation = {
  createdAt?: Date | string | null
  id: string
  organizationName?: string | null
  role?: string | null
}

export type UserInvitationRowProps = {
  invitation: UserInvitation
}

const fallbackRoles: RoleMap = {
  owner: "Owner",
  admin: "Admin",
  member: "Member"
}

const fallbackLocalization = {
  accept: "Accept",
  rejectInvitation: "Reject invitation"
} satisfies Pick<OrganizationLocalization, "accept" | "rejectInvitation">

function formatInvitationDate(createdAt?: Date | string | null) {
  if (!createdAt) return "—"

  const date = createdAt instanceof Date ? createdAt : new Date(createdAt)

  if (Number.isNaN(date.getTime())) return "—"

  return date.toLocaleString(undefined, {
    dateStyle: "medium",
    timeStyle: "short"
  })
}

export function UserInvitationRow(props: UserInvitationRowProps) {
  const auth = useAuth<OrganizationAuthClient>()
  const organizationPluginConfig = () =>
    auth.plugins.find((plugin) => plugin.id === organizationPlugin.id) as
      | {
          localization?: Pick<
            OrganizationLocalization,
            "accept" | "rejectInvitation"
          >
          roles?: RoleMap
        }
      | undefined
  const organizationLocalization = () =>
    organizationPluginConfig()?.localization ?? fallbackLocalization
  const roles = () => organizationPluginConfig()?.roles ?? fallbackRoles
  const acceptInvitation = useAcceptInvitation(auth.authClient)
  const rejectInvitation = useRejectInvitation(auth.authClient)
  const isPending = () =>
    acceptInvitation.isPending || rejectInvitation.isPending
  const roleLabel = () =>
    roles()[props.invitation.role ?? ""] ?? props.invitation.role ?? "Member"

  return (
    <div class="flex items-center gap-3">
      <div class="flex size-10 shrink-0 items-center justify-center rounded-md bg-muted">
        <Clock class="size-4" />
      </div>
      <div class="flex min-w-0 flex-col">
        <div class="flex items-center gap-1.5">
          <span class="truncate font-medium text-sm leading-tight">
            {props.invitation.organizationName ?? "Organization"}
          </span>
          <span class="rounded-md bg-muted px-2 py-1 font-medium text-muted-foreground text-xs">
            {roleLabel()}
          </span>
        </div>
        <span class="truncate text-muted-foreground text-xs">
          {formatInvitationDate(props.invitation.createdAt)}
        </span>
      </div>
      <div class="ml-auto flex shrink-0 items-center gap-2">
        <Button
          disabled={isPending()}
          onClick={() =>
            acceptInvitation.mutate({ invitationId: props.invitation.id })
          }
          size="sm"
          type="button"
          variant="outline"
        >
          <Check class="size-4" />
          {organizationLocalization().accept}
        </Button>
        <Button
          aria-label={organizationLocalization().rejectInvitation}
          class="text-destructive"
          disabled={isPending()}
          onClick={() =>
            rejectInvitation.mutate({ invitationId: props.invitation.id })
          }
          size="icon-sm"
          type="button"
          variant="outline"
        >
          <X class="size-4" />
        </Button>
      </div>
    </div>
  )
}

import { Skeleton } from "@/components/ui/skeleton"

export function UserInvitationRowSkeleton() {
  return (
    <div class="flex items-center gap-3">
      <Skeleton class="size-10 shrink-0 rounded-md" />
      <div class="flex flex-col gap-1">
        <Skeleton class="h-4 w-40 rounded-md" />
        <Skeleton class="h-3 w-28 rounded-md" />
      </div>
    </div>
  )
}

import { organizationLocalization } from "@better-auth-ui/core/plugins/organization"
import { Send } from "lucide-solid"

export function UserInvitationsEmpty() {
  return (
    <div class="flex flex-col items-center gap-4 p-4 text-center">
      <div class="flex size-12 items-center justify-center rounded-full bg-muted">
        <Send class="size-5" />
      </div>
      <div class="flex flex-col gap-2">
        <p class="font-semibold text-foreground text-sm">
          {organizationLocalization.noInvitations}
        </p>
        <span class="text-muted-foreground text-sm">
          {organizationLocalization.userInvitationsEmptyDescription}
        </span>
      </div>
    </div>
  )
}

import type { OrganizationLocalization } from "@better-auth-ui/core/plugins/organization"
import { useAuth } from "@better-auth-ui/solid"
import type { OrganizationAuthClient } from "@better-auth-ui/solid/plugins/organization"
import { useCreateOrganization } from "@better-auth-ui/solid/plugins/organization"
import { BriefcaseBusiness, LoaderCircle } from "lucide-solid"
import { createEffect, createSignal } from "solid-js"
import { Button } from "@/components/ui/button"
import {
  Dialog,
  DialogClose,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle
} from "@/components/ui/dialog"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { organizationPlugin } from "@/lib/auth/organization-plugin"
import { SlugField, sanitizeSlug } from "./slug-field"

export type CreateOrganizationDialogProps = {
  open: boolean
  onOpenChange: (open: boolean) => void
}

const organizationFallbackLocalization = {
  createOrganization: "Create organization",
  name: "Name",
  namePlaceholder: "Enter the organization name",
  organizationsDescription:
    "Create an organization to collaborate with others and manage shared access."
} satisfies Pick<
  OrganizationLocalization,
  "createOrganization" | "name" | "namePlaceholder" | "organizationsDescription"
>

export function CreateOrganizationDialog(props: CreateOrganizationDialogProps) {
  const auth = useAuth<OrganizationAuthClient>()
  const [name, setName] = createSignal("")
  const [slug, setSlug] = createSignal("")
  const [slugEdited, setSlugEdited] = createSignal(false)
  const createOrganization = useCreateOrganization(auth.authClient, {
    onSuccess: () => props.onOpenChange(false)
  })
  const organizationPluginConfig = () =>
    auth.plugins.find((plugin) => plugin.id === organizationPlugin.id) as
      | { localization?: OrganizationLocalization }
      | undefined
  const localization = () =>
    organizationPluginConfig()?.localization ?? organizationFallbackLocalization

  createEffect(() => {
    if (!props.open) {
      setName("")
      setSlug("")
      setSlugEdited(false)
      return
    }

    if (slugEdited()) return

    setSlug(sanitizeSlug(name()))
  })

  const handleSubmit = (event: SubmitEvent) => {
    event.preventDefault()

    createOrganization.mutate({
      name: name(),
      slug: slug()
    })
  }

  return (
    <Dialog open={props.open} onOpenChange={props.onOpenChange}>
      <DialogContent>
        <form class="flex flex-col gap-6" onSubmit={handleSubmit}>
          <DialogHeader>
            <div class="flex size-10 items-center justify-center rounded-md bg-muted">
              <BriefcaseBusiness class="size-4.5" />
            </div>
            <DialogTitle>{localization().createOrganization}</DialogTitle>
            <DialogDescription>
              {localization().organizationsDescription}
            </DialogDescription>
          </DialogHeader>

          <div class="grid gap-2">
            <Label for="create-organization-name">{localization().name}</Label>
            <Input
              autofocus
              disabled={createOrganization.isPending}
              id="create-organization-name"
              name="name"
              onInput={(event) => setName(event.currentTarget.value)}
              placeholder={localization().namePlaceholder}
              required
              value={name()}
            />
          </div>

          <SlugField
            disabled={createOrganization.isPending}
            id="create-organization-slug"
            onChange={(value) => {
              setSlug(value)
              setSlugEdited(true)
            }}
            value={slug()}
          />

          <DialogFooter>
            <DialogClose
              as={Button}
              disabled={createOrganization.isPending}
              type="button"
              variant="outline"
            >
              {auth.localization.settings.cancel}
            </DialogClose>
            <Button disabled={createOrganization.isPending} type="submit">
              {createOrganization.isPending ? (
                <>
                  <LoaderCircle class="size-4 animate-spin" />
                  {localization().createOrganization}
                </>
              ) : (
                localization().createOrganization
              )}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  )
}

import type { OrganizationLocalization } from "@better-auth-ui/core/plugins/organization"
import { useAuth } from "@better-auth-ui/solid"
import type { OrganizationAuthClient } from "@better-auth-ui/solid/plugins/organization"
import { useCheckOrganizationSlug } from "@better-auth-ui/solid/plugins/organization"
import { createDebounce } from "@solid-primitives/debounce"
import { Check, LoaderCircle, X } from "lucide-solid"
import { createEffect } from "solid-js"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { organizationPlugin } from "@/lib/auth/organization-plugin"

export type SlugFieldProps = {
  value: string
  onChange: (value: string) => void
  currentSlug?: string
  disabled?: boolean
  id?: string
}

export function sanitizeSlug(value: string) {
  return value.toLowerCase().replace(/[^a-z0-9]+/g, "-")
}

const organizationFallbackLocalization = {
  slug: "Slug",
  slugPlaceholder: "organization-slug"
} satisfies Pick<OrganizationLocalization, "slug" | "slugPlaceholder">

export function SlugField(props: SlugFieldProps) {
  const auth = useAuth<OrganizationAuthClient>()
  const checkOrganizationSlug = useCheckOrganizationSlug(auth.authClient)
  const organizationPluginConfig = () =>
    auth.plugins.find((plugin) => plugin.id === organizationPlugin.id) as
      | {
          checkSlug?: boolean
          localization?: Pick<
            OrganizationLocalization,
            "slug" | "slugPlaceholder"
          >
        }
      | undefined
  const localization = () =>
    organizationPluginConfig()?.localization ?? organizationFallbackLocalization
  const checkSlug = () => organizationPluginConfig()?.checkSlug ?? true
  const shouldCheckSlug = () =>
    checkSlug() &&
    !!props.value.trim() &&
    props.value.trim() !== props.currentSlug

  const debouncedCheck = createDebounce((slug: string) => {
    checkOrganizationSlug.mutate({ slug })
  }, 300)

  createEffect(() => {
    if (!shouldCheckSlug()) {
      checkOrganizationSlug.reset()
      return
    }

    debouncedCheck(props.value.trim())
  })

  return (
    <div class="grid gap-2">
      <Label for={props.id ?? "slug"}>{localization().slug}</Label>
      <div class="relative">
        <Input
          id={props.id ?? "slug"}
          name="slug"
          value={props.value}
          onInput={(event) =>
            props.onChange(sanitizeSlug(event.currentTarget.value))
          }
          placeholder={localization().slugPlaceholder}
          required
          disabled={props.disabled}
          class="pr-10"
        />
        {shouldCheckSlug() ? (
          <span class="absolute inset-y-0 right-3 inline-flex items-center">
            {checkOrganizationSlug.data?.status ? (
              <Check class="size-4 text-foreground" />
            ) : checkOrganizationSlug.error ? (
              <X class="size-4 text-destructive" />
            ) : (
              <LoaderCircle class="size-4 animate-spin text-muted-foreground" />
            )}
          </span>
        ) : null}
      </div>
    </div>
  )
}

import { useAuth } from "@better-auth-ui/solid"
import { For } from "solid-js"
import type { OrganizationCardsPlugin } from "@/components/auth/settings/shared/types"
import { OrganizationDangerZone } from "./organization-danger-zone"
import { OrganizationProfile } from "./organization-profile"

export type OrganizationSettingsProps = {
  class?: string
}

export function OrganizationSettings(props: OrganizationSettingsProps) {
  const auth = useAuth()
  const organizationCards = () =>
    (auth.plugins as OrganizationCardsPlugin[]).flatMap(
      (plugin) => plugin.organizationCards ?? []
    )

  return (
    <div class={props.class ?? "grid gap-4 md:gap-6"}>
      <OrganizationProfile />
      <For each={organizationCards()}>
        {(OrganizationCard) => <OrganizationCard />}
      </For>
      <OrganizationDangerZone />
    </div>
  )
}

import type { OrganizationLocalization } from "@better-auth-ui/core/plugins/organization"
import { useAuth } from "@better-auth-ui/solid"
import type { OrganizationAuthClient } from "@better-auth-ui/solid/plugins/organization"
import {
  useActiveOrganization,
  useUpdateOrganization
} from "@better-auth-ui/solid/plugins/organization"
import { createEffect, createSignal, Show } from "solid-js"
import { toast } from "solid-sonner"
import { Button } from "@/components/ui/button"
import { Card, CardContent } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Skeleton } from "@/components/ui/skeleton"
import { organizationPlugin } from "@/lib/auth/organization-plugin"
import { ChangeOrganizationLogo } from "./change-organization-logo"
import { SlugField } from "./slug-field"

export type OrganizationProfileProps = {
  class?: string
}

const fallbackLocalization = {
  organizationProfile: "Organization profile",
  name: "Name",
  namePlaceholder: "Enter the organization name",
  organizationUpdatedSuccess: "Organization updated successfully"
} satisfies Pick<
  OrganizationLocalization,
  | "organizationProfile"
  | "name"
  | "namePlaceholder"
  | "organizationUpdatedSuccess"
>

export function OrganizationProfile(props: OrganizationProfileProps) {
  const auth = useAuth<OrganizationAuthClient>()
  const activeOrganization = useActiveOrganization(auth.authClient)
  const updateOrganization = useUpdateOrganization(auth.authClient, {
    onSuccess: () => toast.success(localization().organizationUpdatedSuccess)
  })
  const [name, setName] = createSignal("")
  const [slug, setSlug] = createSignal("")
  const organizationPluginConfig = () =>
    auth.plugins.find((plugin) => plugin.id === organizationPlugin.id) as
      | { localization?: OrganizationLocalization }
      | undefined
  const localization = () =>
    organizationPluginConfig()?.localization ?? fallbackLocalization

  createEffect(() => {
    const organization = activeOrganization.data

    if (!organization) return

    setName(organization.name)
    setSlug(organization.slug)
  })

  const handleSubmit = (event: SubmitEvent) => {
    event.preventDefault()

    updateOrganization.mutate({ data: { name: name(), slug: slug() } })
  }

  return (
    <div class={props.class}>
      <h2 class="mb-3 font-semibold text-sm">
        {localization().organizationProfile}
      </h2>
      <Card>
        <CardContent>
          <form class="flex flex-col gap-4" onSubmit={handleSubmit}>
            <ChangeOrganizationLogo class="-ml-1 grid gap-2" />

            <Show
              when={activeOrganization.data}
              fallback={
                <div class="grid gap-4">
                  <Skeleton class="h-10 rounded-md" />
                  <Skeleton class="h-10 rounded-md" />
                </div>
              }
            >
              {(organization) => (
                <>
                  <div class="grid gap-2">
                    <Label for="organization-profile-name">
                      {localization().name}
                    </Label>
                    <Input
                      disabled={updateOrganization.isPending}
                      id="organization-profile-name"
                      name="name"
                      onInput={(event) => setName(event.currentTarget.value)}
                      placeholder={localization().namePlaceholder}
                      required
                      value={name()}
                    />
                  </div>

                  <SlugField
                    currentSlug={organization().slug}
                    disabled={updateOrganization.isPending}
                    id="organization-profile-slug"
                    onChange={setSlug}
                    value={slug()}
                  />
                </>
              )}
            </Show>

            <Button
              class="mt-1 w-fit"
              disabled={
                !activeOrganization.data || updateOrganization.isPending
              }
              size="sm"
              type="submit"
            >
              {auth.localization.settings.saveChanges}
            </Button>
          </form>
        </CardContent>
      </Card>
    </div>
  )
}

import type { Organization } from "better-auth/client"
import { BriefcaseBusiness } from "lucide-solid"
import type { JSX } from "solid-js"
import { Show } from "solid-js"
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar"
import { Skeleton } from "@/components/ui/skeleton"
import { cn } from "@/lib/utils"

export type OrganizationLogoSize = "sm" | "md" | "lg"

export type OrganizationLogoProps = {
  class?: string
  fallback?: JSX.Element
  isPending?: boolean
  organization?: Partial<Organization>
  size?: OrganizationLogoSize
}

const sizeClass: Record<OrganizationLogoSize, string> = {
  sm: "size-8",
  md: "size-10",
  lg: "size-20"
}

function getInitials(name?: string | null) {
  const normalized = name?.trim()

  if (!normalized) return null

  return normalized.slice(0, 2).toUpperCase()
}

export function OrganizationLogo(props: OrganizationLogoProps) {
  const size = () => props.size ?? "md"
  const logo = () => props.organization?.logo?.trim()
  const label = () => props.organization?.name ?? "Organization"
  const fallback = () =>
    props.fallback ??
    getInitials(props.organization?.name) ?? (
      <BriefcaseBusiness class="size-4" />
    )

  return (
    <Show
      when={!props.isPending || props.organization}
      fallback={
        <Skeleton class={cn("rounded-full", sizeClass[size()], props.class)} />
      }
    >
      <Avatar
        class={cn(
          "rounded-full bg-muted text-muted-foreground",
          sizeClass[size()],
          props.class
        )}
      >
        <Show when={logo()}>
          {(src) => <AvatarImage alt={label()} src={src()} />}
        </Show>
        <AvatarFallback class="rounded-full bg-muted text-muted-foreground">
          {fallback()}
        </AvatarFallback>
      </Avatar>
    </Show>
  )
}

import { fileToBase64 } from "@better-auth-ui/core"
import type { OrganizationLocalization } from "@better-auth-ui/core/plugins/organization"
import { useAuth } from "@better-auth-ui/solid"
import type { OrganizationAuthClient } from "@better-auth-ui/solid/plugins/organization"
import {
  useActiveOrganization,
  useUpdateOrganization
} from "@better-auth-ui/solid/plugins/organization"
import { Trash2, Upload } from "lucide-solid"
import { createSignal, Show } from "solid-js"
import { toast } from "solid-sonner"
import { Button } from "@/components/ui/button"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger
} from "@/components/ui/dropdown-menu"
import { Label } from "@/components/ui/label"
import { organizationPlugin } from "@/lib/auth/organization-plugin"
import { OrganizationLogo } from "./organization-logo"

export type ChangeOrganizationLogoProps = {
  class?: string
}

type LogoConfig = {
  enabled?: boolean
  resize?: (file: File, size?: number, extension?: string) => Promise<File>
  size?: number
  extension?: string
  upload?: (file: File) => Promise<string>
  delete?: (url: string) => Promise<void>
}

const fallbackLocalization = {
  logo: "Logo",
  changeLogo: "Change logo",
  uploadLogo: "Upload logo",
  deleteLogo: "Delete logo",
  logoChangedSuccess: "Logo updated successfully",
  logoDeletedSuccess: "Logo removed successfully"
} satisfies Pick<
  OrganizationLocalization,
  | "logo"
  | "changeLogo"
  | "uploadLogo"
  | "deleteLogo"
  | "logoChangedSuccess"
  | "logoDeletedSuccess"
>

export function ChangeOrganizationLogo(props: ChangeOrganizationLogoProps) {
  const auth = useAuth<OrganizationAuthClient>()
  const activeOrganization = useActiveOrganization(auth.authClient)
  const updateOrganization = useUpdateOrganization(auth.authClient)
  const [isUploadingLogo, setIsUploadingLogo] = createSignal(false)
  const [isDeletingLogo, setIsDeletingLogo] = createSignal(false)
  let logoFileInput: HTMLInputElement | undefined
  const organizationPluginConfig = () =>
    auth.plugins.find((plugin) => plugin.id === organizationPlugin.id) as
      | { logo?: LogoConfig; localization?: OrganizationLocalization }
      | undefined
  const logo = () => organizationPluginConfig()?.logo ?? { enabled: true }
  const localization = () =>
    organizationPluginConfig()?.localization ?? fallbackLocalization
  const isPending = () =>
    activeOrganization.isPending ||
    updateOrganization.isPending ||
    isUploadingLogo() ||
    isDeletingLogo()

  const handleLogoFileChange = async (event: Event) => {
    const input = event.currentTarget as HTMLInputElement
    const file = input.files?.[0]

    if (!file) return

    input.value = ""
    setIsUploadingLogo(true)

    try {
      const resized =
        (await logo().resize?.(file, logo().size, logo().extension)) || file
      const image =
        (await logo().upload?.(resized)) || (await fileToBase64(resized))

      updateOrganization.mutate(
        { data: { logo: image } },
        {
          onSuccess: () => toast.success(localization().logoChangedSuccess)
        }
      )
    } catch (error) {
      if (error instanceof Error) toast.error(error.message)
    } finally {
      setIsUploadingLogo(false)
    }
  }

  const deleteLogo = () => {
    const currentLogo = activeOrganization.data?.logo?.trim()

    updateOrganization.mutate(
      { data: { logo: "" } },
      {
        onSuccess: async () => {
          if (currentLogo) {
            setIsDeletingLogo(true)
            try {
              await logo().delete?.(currentLogo)
            } finally {
              setIsDeletingLogo(false)
            }
          }

          toast.success(localization().logoDeletedSuccess)
        }
      }
    )
  }

  return (
    <Show when={logo().enabled !== false}>
      <div class={props.class ?? "grid gap-2"}>
        <Label>{localization().logo}</Label>
        <input
          accept="image/*"
          class="hidden"
          onChange={handleLogoFileChange}
          ref={logoFileInput}
          type="file"
        />
        <div class="flex items-center gap-4">
          <Button
            class="h-auto w-auto rounded-full p-0"
            disabled={isPending()}
            onClick={() => logoFileInput?.click()}
            type="button"
            variant="ghost"
          >
            <OrganizationLogo
              isPending={activeOrganization.isPending}
              organization={activeOrganization.data ?? undefined}
              size="lg"
            />
          </Button>

          <DropdownMenu>
            <DropdownMenuTrigger
              as={Button}
              class=""
              disabled={!activeOrganization.data || isPending()}
              size="sm"
              variant="secondary"
            >
              {localization().changeLogo}
            </DropdownMenuTrigger>
            <DropdownMenuContent class="min-w-fit">
              <DropdownMenuItem onSelect={() => logoFileInput?.click()}>
                <Upload class="text-muted-foreground" />
                {localization().uploadLogo}
              </DropdownMenuItem>
              <DropdownMenuItem
                disabled={!activeOrganization.data?.logo}
                onSelect={deleteLogo}
                variant="destructive"
              >
                <Trash2 />
                {localization().deleteLogo}
              </DropdownMenuItem>
            </DropdownMenuContent>
          </DropdownMenu>
        </div>
      </div>
    </Show>
  )
}

import type { OrganizationLocalization } from "@better-auth-ui/core/plugins/organization"
import { useAuth } from "@better-auth-ui/solid"
