import type { OrganizationLocalization } from "@better-auth-ui/core/plugins/organization"
import { useAuth } from "@better-auth-ui/solid"
import type {
  InviteMemberParams,
  OrganizationAuthClient
} from "@better-auth-ui/solid/plugins/organization"
import {
  useActiveOrganization,
  useInviteMember
} from "@better-auth-ui/solid/plugins/organization"
import { createEffect, createMemo, createSignal, For } from "solid-js"
import { toast } from "solid-sonner"
import { Button } from "@/components/ui/button"
import {
  Dialog,
  DialogClose,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle
} from "@/components/ui/dialog"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { organizationPlugin } from "@/lib/auth/organization-plugin"

export type InviteMemberDialogProps = {
  open: boolean
  onOpenChange: (open: boolean) => void
}

type RoleMap = Record<string, string>

const fallbackLocalization = {
  admin: "Admin",
  inviteMember: "Invite member",
  inviteMemberDescription:
    "We'll email them a link to join this organization. Choose the role they'll have once they accept.",
  inviteMemberSuccess: "Member invited successfully",
  member: "Member",
  owner: "Owner",
  role: "Role"
} satisfies Pick<
  OrganizationLocalization,
  | "admin"
  | "inviteMember"
  | "inviteMemberDescription"
  | "inviteMemberSuccess"
  | "member"
  | "owner"
  | "role"
>

const fallbackRoles: RoleMap = {
  owner: fallbackLocalization.owner,
  admin: fallbackLocalization.admin,
  member: fallbackLocalization.member
}

function pickDefaultRole(roles: RoleMap) {
  const roleKeys = Object.keys(roles)

  if (roleKeys.includes("member")) return "member"

  return roleKeys.at(-1) ?? ""
}

export function InviteMemberDialog(props: InviteMemberDialogProps) {
  const auth = useAuth<OrganizationAuthClient>()
  const activeOrganization = useActiveOrganization(auth.authClient)
  const organizationPluginConfig = () =>
    auth.plugins.find((plugin) => plugin.id === organizationPlugin.id) as
      | {
          localization?: Pick<
            OrganizationLocalization,
            | "inviteMember"
            | "inviteMemberDescription"
            | "inviteMemberSuccess"
            | "role"
          >
          roles?: RoleMap
        }
      | undefined
  const localization = () =>
    organizationPluginConfig()?.localization ?? fallbackLocalization
  const roles = createMemo(
    () => organizationPluginConfig()?.roles ?? fallbackRoles
  )
  const [email, setEmail] = createSignal("")
  const [role, setRole] = createSignal(pickDefaultRole(roles()))
  const inviteMember = useInviteMember(auth.authClient, {
    onSuccess: () => {
      props.onOpenChange(false)
      toast.success(localization().inviteMemberSuccess)
    }
  })

  createEffect(() => {
    if (!props.open) {
      setEmail("")
      setRole(pickDefaultRole(roles()))
      return
    }

    if (!roles()[role()]) setRole(pickDefaultRole(roles()))
  })

  const handleSubmit = (event: SubmitEvent) => {
    event.preventDefault()

    if (!email().trim() || !roles()[role()]) return

    const payload = {
      email: email().trim(),
      organizationId: activeOrganization.data?.id,
      role: role() as InviteMemberParams["role"]
    } satisfies InviteMemberParams

    inviteMember.mutate(payload)
  }

  return (
    <Dialog open={props.open} onOpenChange={props.onOpenChange}>
      <DialogContent>
        <form class="flex flex-col gap-6" onSubmit={handleSubmit}>
          <DialogHeader>
            <DialogTitle>{localization().inviteMember}</DialogTitle>
            <DialogDescription>
              {localization().inviteMemberDescription}
            </DialogDescription>
          </DialogHeader>

          <div class="grid gap-2">
            <Label for="invite-member-email">
              {auth.localization.auth.email}
            </Label>
            <Input
              autofocus
              disabled={inviteMember.isPending}
              id="invite-member-email"
              name="email"
              onInput={(event) => setEmail(event.currentTarget.value)}
              required
              type="email"
              value={email()}
            />
          </div>

          <div class="grid gap-2">
            <Label for="invite-member-role">{localization().role}</Label>
            <select
              class="flex h-9 w-full rounded-md border border-input bg-background px-3 py-1 text-sm shadow-sm outline-none transition-colors focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:cursor-not-allowed disabled:opacity-50"
              disabled={inviteMember.isPending}
              id="invite-member-role"
              onChange={(event) => setRole(event.currentTarget.value)}
              value={role()}
            >
              <For each={Object.entries(roles())}>
                {([value, label]) => <option value={value}>{label}</option>}
              </For>
            </select>
          </div>

          <DialogFooter>
            <DialogClose
              as={Button}
              disabled={inviteMember.isPending}
              type="button"
              variant="outline"
            >
              {auth.localization.settings.cancel}
            </DialogClose>
            <Button
              disabled={
                inviteMember.isPending || !email().trim() || !roles()[role()]
              }
              type="submit"
            >
              {localization().inviteMember}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  )
}

import type { OrganizationLocalization } from "@better-auth-ui/core/plugins/organization"
import { organizationLocalization } from "@better-auth-ui/core/plugins/organization"
import { useAuth } from "@better-auth-ui/solid"
import type { OrganizationAuthClient } from "@better-auth-ui/solid/plugins/organization"
import { useSetActiveOrganization } from "@better-auth-ui/solid/plugins/organization"
import { useNavigate } from "@tanstack/solid-router"
import type { Organization } from "better-auth/client"
import { Settings as SettingsIcon } from "lucide-solid"
import { Show } from "solid-js"
import { Button } from "@/components/ui/button"
import { Spinner } from "@/components/ui/spinner"
import { organizationPlugin } from "@/lib/auth/organization-plugin"
import { OrganizationView } from "./organization-view"

export type OrganizationRowProps = {
  organization: Organization
}

type OrganizationPluginConfig = {
  slug?: string | null
  localization?: Pick<OrganizationLocalization, "manage">
}

export function OrganizationRow(props: OrganizationRowProps) {
  const auth = useAuth<OrganizationAuthClient>()
  const client = auth.authClient
  const navigate = useNavigate()
  const organizationPluginConfig = () =>
    auth.plugins.find((plugin) => plugin.id === organizationPlugin.id) as
      | OrganizationPluginConfig
      | undefined
  const localization = () =>
    organizationPluginConfig()?.localization ?? organizationLocalization
  const isSlugMode = () => {
    const plugin = organizationPluginConfig()

    if (!plugin) return false

    return plugin.slug !== undefined
  }
  const organizationViewPaths = () =>
    organizationPlugin().viewPaths.organization ?? { settings: "settings" }

  const navigateToOrganization = () => {
    navigate({
      to: "/organization/$slug/$path",
      params: {
        slug: props.organization.slug,
        path: organizationViewPaths().settings
      }
    })
  }
  const setActiveOrganization = useSetActiveOrganization(client, {
    onSuccess: navigateToOrganization
  })

  const manageOrganization = () => {
    if (isSlugMode()) {
      navigateToOrganization()
      return
    }

    setActiveOrganization.mutate({
      organizationId: props.organization.id
    })
  }

  return (
    <div class="flex items-center gap-3">
      <OrganizationView organization={props.organization} />

      <Button
        class="ml-auto shrink-0"
        variant="outline"
        size="sm"
        disabled={setActiveOrganization.isPending}
        onClick={manageOrganization}
        aria-label={localization().manage}
      >
        <Show
          when={setActiveOrganization.isPending}
          fallback={<SettingsIcon />}
        >
          <Spinner />
        </Show>

        {localization().manage}
      </Button>
    </div>
  )
}

import {
  organizationLocalization as defaultOrganizationLocalization,
  type OrganizationLocalization
} from "@better-auth-ui/core/plugins/organization"
import { useAuth, useSession } from "@better-auth-ui/solid"
import type { OrganizationAuthClient } from "@better-auth-ui/solid/plugins/organization"
import {
  useActiveOrganization,
  useListOrganizations,
  useSetActiveOrganization
} from "@better-auth-ui/solid/plugins/organization"
import { useNavigate } from "@tanstack/solid-router"
import type { Organization } from "better-auth/client"
import {
  ChevronsUpDown,
  PlusCircle,
  Settings as SettingsIcon
} from "lucide-solid"
import type { JSX } from "solid-js"
import {
  createMemo,
  createSignal,
  For,
  mergeProps,
  onMount,
  Show
} from "solid-js"
import { UserView } from "@/components/auth/user/user-view"
import { Button } from "@/components/ui/button"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger
} from "@/components/ui/dropdown-menu"
import { organizationPlugin } from "@/lib/auth/organization-plugin"
import { cn } from "@/lib/utils"
import { CreateOrganizationDialog } from "./create-organization-dialog"
import { OrganizationView } from "./organization-view"

export type OrganizationSwitcherProps = {
  class?: string
  trigger?: JSX.Element
  hidePersonal?: boolean
  hideSettings?: boolean
  hideSlug?: boolean
  hideCreate?: boolean
  setActive?: (organization: Organization | null) => void
}

type OrganizationPluginConfig = {
  slug?: string | null
  localization?: Pick<
    OrganizationLocalization,
    "createOrganization" | "organization" | "organizations" | "manage"
  >
}

function OrganizationSwitcherTrigger(rawProps: OrganizationSwitcherProps = {}) {
  const props = mergeProps({ hideSlug: true }, rawProps)

  return (
    <Show
      when={props.trigger}
      fallback={
        <Button
          class={cn("h-auto px-2 py-2 text-left", props.class)}
          disabled
          variant="ghost"
        >
          <OrganizationView isPending hideRole hideSlug={props.hideSlug} />
          <ChevronsUpDown class="size-4 shrink-0 text-muted-foreground" />
        </Button>
      }
    >
      {props.trigger}
    </Show>
  )
}

function MountedOrganizationSwitcher(rawProps: OrganizationSwitcherProps = {}) {
  const props = mergeProps({ hideSlug: true }, rawProps)
  const auth = useAuth<OrganizationAuthClient>()
  const client = auth.authClient
  const navigate = useNavigate()
  const session = useSession(client)
  const activeOrganization = useActiveOrganization(client)
  const organizations = useListOrganizations(client)
  const setActiveOrganization = useSetActiveOrganization(client)
  const [createOpen, setCreateOpen] = createSignal(false)
  const [isOpen, setIsOpen] = createSignal(false)
  const organizationPluginConfig = () =>
    auth.plugins.find((plugin) => plugin.id === organizationPlugin.id) as
      | OrganizationPluginConfig
      | undefined
  const organizationViewPaths = () =>
    organizationPlugin().viewPaths.organization ?? { settings: "settings" }
  const localization = () =>
    organizationPluginConfig()?.localization ?? defaultOrganizationLocalization
  const isSlugMode = () => {
    const plugin = organizationPluginConfig()

    if (!plugin) return false

    return plugin.slug !== undefined
  }
  const isPending = () =>
    session.isPending ||
    (!!session.data &&
      (organizations.isPending || activeOrganization.isPending))
  const shouldShowSlug = () => !props.hideSlug
  const selectableOrganizations = () =>
    ((organizations.data ?? []) as Organization[]).filter(
      (organization) => organization.id !== activeOrganization.data?.id
    )
  const hasOtherEntries = () =>
    selectableOrganizations().length > 0 ||
    (!!activeOrganization.data && !props.hidePersonal)

  const navigateToOrganization = (organization: Organization) => {
    navigate({
      to: "/organization/$slug/$path",
      params: {
        slug: organization.slug,
        path: organizationViewPaths().settings
      }
    })
  }

  const navigateToPersonal = () => {
    navigate({
      to: "/settings/$path",
      params: { path: auth.viewPaths.settings.account }
    })
  }

  const navigateToActiveOrganizationSettings = () => {
    const active = activeOrganization.data

    if (!active) {
      navigate({
        to: "/settings/$path",
        params: { path: auth.viewPaths.settings.account }
      })
      return
    }

    navigateToOrganization(active as Organization)
  }

  const handleSetActive = (organization: Organization | null) => {
    setIsOpen(false)

    if (organization) props.setActive?.(organization)
    if (!organization) props.setActive?.(null)
    if (props.setActive) return

    if (isSlugMode()) {
      if (organization) {
        navigateToOrganization(organization)
        return
      }

      navigateToPersonal()
      return
    }

    setActiveOrganization.mutate(
      { organizationId: organization?.id ?? null },
      {
        onSuccess: () => {
          if (organization) {
            navigateToOrganization(organization)
            return
          }

          navigateToPersonal()
        }
      }
    )
  }

  return (
    <>
      <DropdownMenu open={isOpen()} onOpenChange={setIsOpen}>
        <Show
          when={props.trigger}
          fallback={
            <DropdownMenuTrigger
              as={Button}
              variant="ghost"
              class={cn("h-auto px-2 py-2 text-left", props.class)}
              disabled={!session.data || isPending()}
            >
              <Show
                when={!isPending()}
                fallback={
                  <OrganizationView
                    isPending
                    hideRole
                    hideSlug={props.hideSlug}
                  />
                }
              >
                <Show
                  when={activeOrganization.data}
                  fallback={
                    <Show
                      when={
                        !props.hidePersonal ? session.data?.user : undefined
                      }
                      fallback={
                        <OrganizationView
                          hideRole
                          hideSlug={props.hideSlug}
                          organization={{
                            name: localization().organization
                          }}
                        />
                      }
                    >
                      {(user) => (
                        <UserView hideSubtitle={props.hideSlug} user={user()} />
                      )}
                    </Show>
                  }
                >
                  {(organization) => (
                    <OrganizationView
                      hideRole
                      hideSlug={!shouldShowSlug()}
                      organization={organization()}
                    />
                  )}
                </Show>
              </Show>

              <ChevronsUpDown class="size-4 shrink-0 text-muted-foreground" />
            </DropdownMenuTrigger>
          }
        >
          <DropdownMenuTrigger as="span" class={props.class}>
            {props.trigger}
          </DropdownMenuTrigger>
        </Show>
        <DropdownMenuContent class="min-w-64 max-w-svw">
          <Show when={activeOrganization.data}>
            {(organization) => (
              <div class="flex items-center justify-between gap-4 px-2 py-2">
                <OrganizationView
                  hideRole
                  hideSlug={props.hideSlug}
                  organization={organization()}
                />

                <Show when={!props.hideSettings}>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={navigateToActiveOrganizationSettings}
                  >
                    <SettingsIcon class="text-muted-foreground" />
                    {localization().manage}
                  </Button>
                </Show>
              </div>
            )}
          </Show>

          <Show
            when={
              !activeOrganization.data && !isPending() && !props.hidePersonal
                ? session.data?.user
                : undefined
            }
          >
            {(resolvedSession) => (
              <div class="flex items-center justify-between gap-4 px-2 py-2">
                <UserView
                  hideSubtitle={props.hideSlug}
                  user={resolvedSession()}
                />

                <Show when={!props.hideSettings}>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={navigateToPersonal}
                  >
                    <SettingsIcon class="text-muted-foreground" />
                    {auth.localization.settings.settings}
                  </Button>
                </Show>
              </div>
            )}
          </Show>

          <DropdownMenuSeparator />

          <Show when={activeOrganization.data && !props.hidePersonal}>
            <DropdownMenuItem onSelect={() => handleSetActive(null)}>
              <UserView hideSubtitle={props.hideSlug} />
            </DropdownMenuItem>
          </Show>

          <For each={selectableOrganizations()}>
            {(organization) => (
              <DropdownMenuItem onSelect={() => handleSetActive(organization)}>
                <OrganizationView
                  hideRole
                  hideSlug={props.hideSlug}
                  organization={organization}
                />
              </DropdownMenuItem>
            )}
          </For>

          <Show when={!props.hideCreate}>
            <Show when={hasOtherEntries()}>
              <DropdownMenuSeparator />
            </Show>

            <DropdownMenuItem
              onSelect={() => {
                setIsOpen(false)
                setCreateOpen(true)
              }}
            >
              <PlusCircle class="text-muted-foreground" />
              {localization().createOrganization}
            </DropdownMenuItem>
          </Show>
        </DropdownMenuContent>
      </DropdownMenu>
      <CreateOrganizationDialog
        open={createOpen()}
        onOpenChange={setCreateOpen}
      />
    </>
  )
}

export function OrganizationSwitcher(props: OrganizationSwitcherProps = {}) {
  const [isMounted, setIsMounted] = createSignal(false)

  onMount(() => setIsMounted(true))

  const content = createMemo(() =>
    isMounted() ? (
      <MountedOrganizationSwitcher {...props} />
    ) : (
      <OrganizationSwitcherTrigger {...props} />
    )
  )

  return <>{content()}</>
}

import type { OrganizationLocalization } from "@better-auth-ui/core/plugins/organization"
import { organizationLocalization } from "@better-auth-ui/core/plugins/organization"
import { useAuth, useSession } from "@better-auth-ui/solid"
import type { OrganizationAuthClient } from "@better-auth-ui/solid/plugins/organization"
import {
  useActiveOrganization,
  useListOrganizationMembers
} from "@better-auth-ui/solid/plugins/organization"
import type { Organization } from "better-auth/client"
import type { ComponentProps } from "solid-js"
import { Show, splitProps } from "solid-js"
import { Badge } from "@/components/ui/badge"
import { organizationPlugin } from "@/lib/auth/organization-plugin"
import { cn } from "@/lib/utils"
import {
  OrganizationLogo,
  type OrganizationLogoSize
} from "./organization-logo"
import { OrganizationViewSkeleton } from "./organization-view-skeleton"

type OrganizationPluginConfig = {
  roles?: Record<string, string>
  localization?: OrganizationLocalization
}

type OrganizationMember = {
  userId: string
  role: string
}

export type OrganizationViewProps = ComponentProps<"div"> & {
  isPending?: boolean
  size?: OrganizationLogoSize
  hideRole?: boolean
  hideSlug?: boolean
  organization?: Partial<Organization>
}

export function OrganizationView(props: OrganizationViewProps) {
  const [local, others] = splitProps(props, [
    "class",
    "isPending",
    "size",
    "hideRole",
    "hideSlug",
    "organization"
  ])
  const auth = useAuth<OrganizationAuthClient>()
  const client = auth.authClient
  const pluginConfig = () =>
    auth.plugins.find((plugin) => plugin.id === organizationPlugin.id) as
      | OrganizationPluginConfig
      | undefined
  const roles = () =>
    pluginConfig()?.roles ?? {
      owner: organizationLocalization.owner,
      admin: organizationLocalization.admin,
      member: organizationLocalization.member
    }
  const session = useSession(client)
  const activeOrganization = useActiveOrganization(client, {
    enabled: !local.organization && !local.isPending
  } as never)
  const resolvedOrganization = () =>
    local.organization ?? activeOrganization.data
  const membersList = useListOrganizationMembers(client, {
    query: { organizationId: resolvedOrganization()?.id },
    enabled: !!resolvedOrganization()?.id && !local.hideRole
  } as never)
  const membership = () =>
    (membersList.data?.members as OrganizationMember[] | undefined)?.find(
      (member) => member.userId === session.data?.user.id
    )

  return (
    <Show
      when={
        !local.isPending &&
        (local.organization || !activeOrganization.isPending) &&
        (local.hideRole ||
          !resolvedOrganization()?.id ||
          !membersList.isPending)
      }
      fallback={
        <OrganizationViewSkeleton
          class={local.class}
          hideSlug={local.hideSlug}
          size={local.size}
        />
      }
    >
      <div
        class={cn("flex min-w-0 items-center gap-2", local.class)}
        {...others}
      >
        <OrganizationLogo
          organization={resolvedOrganization()}
          class={local.size === "sm" ? "size-5" : undefined}
          size={local.size === "lg" ? "md" : "sm"}
        />

        <div class="flex min-w-0 flex-col">
          <div class="flex min-w-0 items-center gap-2">
            <p class="truncate text-sm font-medium leading-tight text-foreground">
              {resolvedOrganization()?.name}
            </p>

            <Show when={!local.hideRole && membership()}>
              {(member) => (
                <Badge variant="secondary" class="-my-0.5 shrink-0">
                  {roles()[member().role] ?? member().role}
                </Badge>
              )}
            </Show>
          </div>

          <Show when={!local.hideSlug}>
            <p class="truncate overflow-x-hidden font-mono text-muted-foreground text-xs leading-tight">
              {resolvedOrganization()?.slug}
            </p>
          </Show>
        </div>
      </div>
    </Show>
  )
}

